function initAnimations(){const observerOptions={root:null,rootMargin:'0px',threshold:0.15};const revealObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('active');observer.unobserve(entry.target);}});},observerOptions);const observeElements=()=>{const revealElements=document.querySelectorAll('.reveal-up:not(.active)');revealElements.forEach(el=> revealObserver.observe(el));};observeElements();let hasCounted=false;const countUp=()=>{const counters=document.querySelectorAll('.counter');counters.forEach(counter=>{const target=+counter.getAttribute('data-target');if(target===0)return;const duration=2000;const increment=target/(duration/16);let current=0;const updateCounter=()=>{current+=increment;if(current < target){counter.innerText=Math.ceil(current).toLocaleString();requestAnimationFrame(updateCounter);}else{counter.innerText=target.toLocaleString();if(target===98)counter.innerText+="%";else counter.innerText+="+";}};updateCounter();});};const statsObserver=new IntersectionObserver((entries)=>{if(entries[0].isIntersecting && !hasCounted){hasCounted=true;countUp();}},{threshold:0.5});const statsSection=document.querySelector('.stats-section');if(statsSection){statsObserver.observe(statsSection);}document.addEventListener('componentLoaded',observeElements);}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initAnimations);}else{initAnimations();}